// ============================================
// FTKMap - راسم الخريطة المشترك (Canvas)
// يُستخدم في صفحة اللاعب وشاشة العرض ولوحة الراوي.
// يستبدل <svg id="mapSvg"> بـ <canvas> في مكانه (نفس المعرف).
// ============================================
window.FTKMap = (function () {
  const NODES = [
    { id: 'h1_0',  col: 0,  y: 0.0, num: 1  },
    { id: 'h1_-1', col: -1, y: 0.5, num: 2  },
    { id: 'h1_1',  col: 1,  y: 0.5, num: 3  },
    { id: 'h2_0',  col: 0,  y: 1.0, num: 4  },
    { id: 'h2_-1', col: -1, y: 1.5, num: 5  },
    { id: 'h2_1',  col: 1,  y: 1.5, num: 6  },
    { id: 'h3_-2', col: -2, y: 2.0, num: 7  },
    { id: 'h3_0',  col: 0,  y: 2.0, num: 8  },
    { id: 'h3_2',  col: 2,  y: 2.0, num: 9  },
    { id: 'h3_-1', col: -1, y: 2.5, num: 10 },
    { id: 'h3_1',  col: 1,  y: 2.5, num: 11 },
    { id: 'h4_-2', col: -2, y: 3.0, num: 12 },
    { id: 'h4_0',  col: 0,  y: 3.0, num: 13 },
    { id: 'h4_2',  col: 2,  y: 3.0, num: 14 },
    { id: 'h4_-3', col: -3, y: 3.5, num: 15 },
    { id: 'h4_-1', col: -1, y: 3.5, num: 16 },
    { id: 'h4_1',  col: 1,  y: 3.5, num: 17 },
    { id: 'h4_3',  col: 3,  y: 3.5, num: 18 },
    { id: 'h5_-2', col: -2, y: 4.0, num: 19 },
    { id: 'h5_0',  col: 0,  y: 4.0, num: 20 },
    { id: 'h5_2',  col: 2,  y: 4.0, num: 21 },
    { id: 'h5_-3', col: -3, y: 4.5, num: 22 },
    { id: 'h5_-1', col: -1, y: 4.5, num: 23 },
    { id: 'h5_1',  col: 1,  y: 4.5, num: 24 },
    { id: 'h5_3',  col: 3,  y: 4.5, num: 25 },
    { id: 'h6_-2', col: -2, y: 5.0, num: 26 },
    { id: 'h6_0',  col: 0,  y: 5.0, num: 27 },
    { id: 'h6_2',  col: 2,  y: 5.0, num: 28 },
    { id: 'h6_-1', col: -1, y: 5.5, num: 29 },
    { id: 'h6_1',  col: 1,  y: 5.5, num: 30 },
    { id: 'h7_0',  col: 0,  y: 6.0, num: 31 },
  ];

  const VICTORY = {
    PIRATE: 'PIRATE_VICTORY',
    SAILOR: 'SAILOR_VICTORY',
    CULT: 'CULT_VICTORY',
  };
  const VICTORY_IDS = new Set([VICTORY.PIRATE, VICTORY.SAILOR, VICTORY.CULT]);

  const EXIT_TABLE = {
    1:  { yellow: 4,  red: 2,    blue: 3    },
    2:  { yellow: 5,  red: 5,    blue: 4    },
    3:  { yellow: 6,  red: 4,    blue: 6    },
    4:  { yellow: 8,  red: 5,    blue: 6    },
    5:  { yellow: 10, red: 7,    blue: 8    },
    6:  { yellow: 11, red: 8,    blue: 9    },
    7:  { yellow: 12, red: 12,   blue: 10   },
    8:  { yellow: 10, red: 10,   blue: 11   },
    9:  { yellow: 14, red: 11,   blue: 14   },
    10: { yellow: 16, red: 12,   blue: 13   },
    11: { yellow: 17, red: 13,   blue: 14   },
    12: { yellow: 19, red: 15,   blue: 16   },
    13: { yellow: 20, red: 16,   blue: 17   },
    14: { yellow: 21, red: 17,   blue: 18   },
    15: { yellow: 19, red: 22,   blue: 19   },
    16: { yellow: 23, red: 19,   blue: 20   },
    17: { yellow: 24, red: 20,   blue: 21   },
    18: { yellow: 21, red: 21,   blue: 25   },
    19: { yellow: 23, red: 26,   blue: 23   },
    20: { yellow: 27, red: 23,   blue: 24   },
    21: { yellow: 24, red: 24,   blue: 28   },
    22: { yellow: VICTORY.PIRATE, red: VICTORY.PIRATE, blue: 26   },
    23: { yellow: 29, red: 26,   blue: 27   },
    24: { yellow: 30, red: 27,   blue: 28   },
    25: { yellow: VICTORY.SAILOR, red: 28,   blue: VICTORY.SAILOR },
    26: { yellow: VICTORY.PIRATE, red: VICTORY.PIRATE, blue: 29   },
    27: { yellow: 31, red: 29,   blue: 30   },
    28: { yellow: VICTORY.SAILOR, red: 30,   blue: VICTORY.SAILOR },
    29: { yellow: VICTORY.PIRATE, red: VICTORY.PIRATE, blue: 31   },
    30: { yellow: VICTORY.SAILOR, red: 31,   blue: VICTORY.SAILOR },
    31: { yellow: VICTORY.CULT,   red: VICTORY.CULT,   blue: VICTORY.CULT   },
  };

  const ACTION_PLACEMENT = {
    'h2_-1': 'cabin_search',
    'h2_1':  'cabin_search',
    'h3_-2': 'cabin_search',
    'h3_0':  'cabin_search',
    'h4_0':  'off_with_tongue',
    'h4_-1': 'flogging',
    'h4_1':  'flogging',
    'h5_-1': 'feed_the_kraken',
    'h5_1':  'feed_the_kraken',
    'h6_0':  'feed_the_kraken',
  };

  const ACTION_ICONS = {
    cabin_search: '🔍',
    off_with_tongue: '🔪',
    flogging: '🪶',
    feed_the_kraken: '🐙',
  };

  const KRAKEN_ZONE = new Set([31]);
  const PIRATE_ZONE = new Set([22, 26, 29]);
  const SAILOR_ZONE = new Set([25, 28, 30]);
  const VICTORY_STYLES = {
    kraken:  { fill: '#221f0f', border: '#ffcc00', icon: '🦑' },
    pirate:  { fill: '#3a1a1a', border: '#df2935', icon: '🏴‍☠️' },
    sailor:  { fill: '#05182d', border: '#0044cc', icon: '⚓' },
  };

  function victoryStyleFor(num) {
    if (KRAKEN_ZONE.has(num)) return VICTORY_STYLES.kraken;
    if (PIRATE_ZONE.has(num)) return VICTORY_STYLES.pirate;
    if (SAILOR_ZONE.has(num)) return VICTORY_STYLES.sailor;
    return null;
  }

  function buildLocalMap() {
    const byNum = {};
    for (const n of NODES) byNum[n.num] = n;
    const hexes = {};
    for (const n of NODES) {
      const table = EXIT_TABLE[n.num];
      const exits = {};
      if (table) {
        for (const color of ['yellow', 'red', 'blue']) {
          const t = table[color];
          if (typeof t === 'string') exits[color] = t;
          else exits[color] = byNum[t] ? byNum[t].id : null;
        }
      }
      hexes[n.id] = {
        id: n.id,
        row: Math.floor(n.y) + 1,
        x: n.col,
        y: n.y,
        num: n.num,
        action: ACTION_PLACEMENT[n.id] || null,
        exits,
      };
    }
    return hexes;
  }

  const LOCAL_MAP = buildLocalMap();

  // ---- تنسيق الرسم ----
  const hexRadius = 90;
  const gridOffsetX = 0;
  const gridOffsetY = 116;
  const widthSpacer = 1.074;
  const heightSpacer = 1.168;
  const hexHeight = Math.sqrt(3) * hexRadius * heightSpacer;

  let canvas = null, ctx = null;
  let lastState = null;
  let lastShipId = null;

  const log = (...a) => console.log('[FTKMap]', ...a);
  const warn = (...a) => console.warn('[FTKMap]', ...a);

  function pixelOf(hex) {
    return {
      cx: (canvas.width / 2) + gridOffsetX + (hex.x * (1.5 * hexRadius * widthSpacer)),
      cy: (canvas.height - 155) + gridOffsetY - (hex.y * hexHeight),
    };
  }

  const bgImg = new Image();
  bgImg.src = '/map.jpg';
  bgImg.onload = function () {
    if (canvas && lastState) drawMap(lastState, lastShipId);
  };

  const shipImage = new Image();
  shipImage.src = 'data:image/png;base64,';
  shipImage.onload = function () {
    if (canvas && lastState) drawMap(lastState, lastShipId);
  };

  let shipAngle = 0;
  let animFrame = null;

  function animateShip() {
    shipAngle += 0.03;
    if (canvas && lastState) {
      drawMap(lastState, lastShipId);
    }
    animFrame = requestAnimationFrame(animateShip);
  }

  function drawFancyShip(ctx, cx, cy) {
    if (!shipImage.complete) return;
    ctx.save();
    ctx.translate(cx, cy);
    const rock = Math.sin(shipAngle) * 0.08;
    ctx.rotate(rock);
    const bob = Math.sin(shipAngle * 0.7) * 4;
    const size = 120;
    ctx.globalAlpha = 1.0;
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';
    ctx.drawImage(shipImage, -size / 2, -size / 2 + bob, size, size);
    ctx.restore();
  }

  function getHexes(state) {
    if (state && state.hexes && Object.keys(state.hexes).length) {
      return state.hexes;
    }
    return LOCAL_MAP;
  }

  function drawMap(state, shipNodeId) {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (bgImg.complete) {
      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
    }

    const hexes = getHexes(state);
    if (shipNodeId && hexes[shipNodeId]) {
      const hex = hexes[shipNodeId];
      const { cx, cy } = pixelOf(hex);
      drawFancyShip(ctx, cx, cy);
    }
  }

  function build(el, opts) {
    opts = opts || {};
    let c = el;
    if (el && el.tagName && String(el.tagName).toLowerCase() === 'svg') {
      c = document.createElement('canvas');
      c.id = el.id;
      if (el.className) c.className = el.className;
      const aria = el.getAttribute && el.getAttribute('aria-label');
      if (aria) c.setAttribute('aria-label', aria);
      if (el.parentNode) el.parentNode.replaceChild(c, el);
      log('استُبدل <svg id="' + c.id + '"> بـ <canvas>');
    }
    c.width = 1250;
    c.height = 1250;
    canvas = c;
    ctx = c.getContext('2d');
    c._ftk = { ctx, lastShip: null };
    log('Canvas renderer ready (single mode for all modes)');

    if (typeof opts.onHexClick === 'function') {
      c.addEventListener('click', function (ev) {
        const rect = c.getBoundingClientRect();
        const sx = c.width / (rect.width || c.width);
        const sy = c.height / (rect.height || c.height);
        const px = (ev.clientX - rect.left) * sx;
        const py = (ev.clientY - rect.top) * sy;
        const hexes = (c._ftk && c._ftk.hexes) || LOCAL_MAP;
        let best = null, bd = Infinity;
        for (const id in hexes) {
          const { cx, cy } = pixelOf(hexes[id]);
          const d = (cx - px) * (cx - px) + (cy - py) * (cy - py);
          if (d < bd) { bd = d; best = id; }
        }
        if (best && bd <= hexRadius * hexRadius) opts.onHexClick(best);
      });
    }

    lastState = { mode: 'long' };
    lastShipId = 'h1_0';
    drawMap(lastState, lastShipId);
    if (!animFrame) animateShip();
    return c;
  }

  function update(el, state) {
    state = state || {};
    const c = el && el._ftk ? el : null;
    if (!c) { warn('update: canvas غير مهيّأ — تم تخطّي التحديث'); return; }
    canvas = c;
    ctx = c._ftk.ctx;

    const hexes = getHexes(state);
    c._ftk.hexes = hexes;
    lastState = state;

    let shipNodeId = null;
    if (state.shipHex) {
      if (hexes[state.shipHex]) {
        shipNodeId = state.shipHex;
        if (shipNodeId !== c._ftk.lastShip) {
          log('Ship:', state.shipHex, '→', shipNodeId, '(mode: long)');
          c._ftk.lastShip = shipNodeId;
        }
      } else {
        warn('shipHex غير معروف على الخريطة:', state.shipHex);
      }
    }
    lastShipId = shipNodeId;
    drawMap(state, shipNodeId);
    if (!animFrame) animateShip();
  }

  return { build, update };
})();
